/**
 * Email notification handler — formats and sends email notifications
 * in response to order status change events.
 *
 * Subscribes to the EventBus following the same pattern as NotificationService.
 * In production, the `sendEmail` method would integrate with an SMTP provider;
 * here it stores emails in memory for testability.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface Email {
  id: string;
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

let nextEmailId = 1;

function generateEmailId(): string {
  return `email-${String(nextEmailId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextEmailId = 1;
}

const STATUS_LABELS: Record<string, string> = {
  pending: 'Order Placed',
  confirmed: 'Order Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

function statusLabel(status: string): string {
  return STATUS_LABELS[status] ?? status;
}

const STATUS_MESSAGES: Record<string, string> = {
  confirmed: 'Great news! Your order has been confirmed and is being prepared.',
  shipped: 'Your order is on its way! You will receive it soon.',
  delivered: 'Your order has been delivered. We hope you enjoy your purchase!',
  cancelled: 'Your order has been cancelled. If this was unexpected, please contact support.',
};

function statusMessage(newStatus: string): string {
  return STATUS_MESSAGES[newStatus] ?? `Your order status has been updated to ${statusLabel(newStatus)}.`;
}

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: Email[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers on the EventBus.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send a welcome/confirmation email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${(item.unitPrice * item.quantity).toFixed(2)}</td></tr>`,
      )
      .join('\n');

    const itemList = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} ($${(item.unitPrice * item.quantity).toFixed(2)})`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Hi ${event.user.name},</p>
<p>Thank you for your order <strong>${event.order.id}</strong>!</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Subtotal</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Hi ${event.user.name},

Thank you for your order ${event.order.id}!

Items:
${itemList}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Handle order status change — send a status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status change email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const label = statusLabel(event.newStatus);
    const message = statusMessage(event.newStatus);

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> status has changed.</p>
<p><strong>Status:</strong> ${label}</p>
<p>${message}</p>`;

    const textBody = `Order Status Update

Your order ${event.order.id} status has changed.

Status: ${label}

${message}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${event.order.id} - ${label}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send an email. In production this would call an SMTP/email API provider.
   * For now, stores in memory.
   */
  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: Email = {
      id: generateEmailId(),
      to: params.to,
      subject: params.subject,
      htmlBody: params.htmlBody,
      textBody: params.textBody,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent: ${email.id} to ${params.to} — "${params.subject}"`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): Email[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails for a specific recipient.
   */
  getEmailsForRecipient(recipient: string): Email[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get sent email count.
   */
  getEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailNotificationHandler,
  resetEmailIdCounter,
} from '../../src/notifications/email-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(
  newStatus: string,
  previousStatus: string = 'pending',
): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: newStatus as OrderStatusChangedEvent['order']['status'],
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date(),
  };
}

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
    resetEmailIdCounter();
  });

  describe('order:created email', () => {
    it('should send a confirmation email when an order is created', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include item details in the HTML body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('$20.00');
      expect(email.htmlBody).toContain('Order Confirmation');
    });

    it('should include item details in the text body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('$20.00');
    });

    it('should include user name in email body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Alice');
      expect(email.textBody).toContain('Alice');
    });

    it('should handle multiple items', async () => {
      const event = makeOrderCreatedEvent();
      event.order.items = [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
      ];
      event.order.total = 45;

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      expect(email.textBody).toContain('$45.00');
    });
  });

  describe('order:status-changed email', () => {
    it('should send an email when order status changes to confirmed', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('Order Confirmed');
      expect(emails[0]?.htmlBody).toContain('confirmed');
      expect(emails[0]?.textBody).toContain('confirmed');
    });

    it('should send an email when order status changes to shipped', async () => {
      await eventBus.emit(makeStatusChangedEvent('shipped', 'confirmed'));

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Shipped');
      expect(email.htmlBody).toContain('on its way');
      expect(email.textBody).toContain('on its way');
    });

    it('should send an email when order status changes to delivered', async () => {
      await eventBus.emit(makeStatusChangedEvent('delivered', 'shipped'));

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Delivered');
      expect(email.htmlBody).toContain('delivered');
      expect(email.textBody).toContain('delivered');
    });

    it('should send an email when order status changes to cancelled', async () => {
      await eventBus.emit(makeStatusChangedEvent('cancelled'));

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Cancelled');
      expect(email.htmlBody).toContain('cancelled');
      expect(email.textBody).toContain('contact support');
    });

    it('should include order ID in subject and body', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('order-1');
      expect(email.htmlBody).toContain('order-1');
      expect(email.textBody).toContain('order-1');
    });
  });

  describe('email management', () => {
    it('should generate sequential email IDs', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));
      await eventBus.emit(makeStatusChangedEvent('shipped', 'confirmed'));

      const emails = handler.getSentEmails();
      expect(emails[0]?.id).toBe('email-0001');
      expect(emails[1]?.id).toBe('email-0002');
    });

    it('should count emails', async () => {
      expect(handler.getEmailCount()).toBe(0);

      await eventBus.emit(makeStatusChangedEvent('confirmed'));
      expect(handler.getEmailCount()).toBe(1);

      await eventBus.emit(makeStatusChangedEvent('shipped', 'confirmed'));
      expect(handler.getEmailCount()).toBe(2);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear emails', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));
      expect(handler.getEmailCount()).toBe(1);

      handler.clearEmails();
      expect(handler.getEmailCount()).toBe(0);
    });

    it('should return copies from getSentEmails', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));

      const emails1 = handler.getSentEmails();
      const emails2 = handler.getSentEmails();
      expect(emails1).not.toBe(emails2);
      expect(emails1).toEqual(emails2);
    });
  });

  describe('integration with EventBus', () => {
    it('should work alongside other handlers on the same EventBus', async () => {
      const externalCalls: string[] = [];
      eventBus.on('order:status-changed', () => {
        externalCalls.push('called');
      });

      await eventBus.emit(makeStatusChangedEvent('shipped', 'confirmed'));

      expect(handler.getEmailCount()).toBe(1);
      expect(externalCalls).toHaveLength(1);
    });

    it('should handle multiple status changes in sequence', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));
      await eventBus.emit(makeStatusChangedEvent('shipped', 'confirmed'));
      await eventBus.emit(makeStatusChangedEvent('delivered', 'shipped'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(3);
      expect(emails[0]?.subject).toContain('Order Confirmed');
      expect(emails[1]?.subject).toContain('Shipped');
      expect(emails[2]?.subject).toContain('Delivered');
    });

    it('should log events in the EventBus event log', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed'));

      const log = eventBus.getEventLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.type).toBe('order:status-changed');
    });
  });
});

